<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\Repositories\ControlEscaneres\Contracts\ScannerDashboardQueryInterface;
final class PdoScannerDashboardQuery extends AbstractPdoRepository implements ScannerDashboardQueryInterface{public function countByStatus():array{return$this->stmt('SELECT estado,COUNT(*) total FROM scanners GROUP BY estado')->fetchAll(\PDO::FETCH_ASSOC);}public function countActive():int{return(int)$this->stmt('SELECT COUNT(*) FROM scanners WHERE activo=1')->fetchColumn();}public function countOutOfService():int{return(int)$this->stmt("SELECT COUNT(*) FROM scanners WHERE activo=1 AND estado IN('mantenimiento','pendiente_reparacion','baja_definitiva','extraviado')")->fetchColumn();}public function countMovementsForDay(\DateTimeImmutable$d):int{$f=$d->setTime(0,0);return(int)$this->stmt('SELECT COUNT(*) FROM scanner_movimientos WHERE entregado_at>=:f AND entregado_at<:t',['f'=>$f->format('Y-m-d H:i:s'),'t'=>$f->modify('+1 day')->format('Y-m-d H:i:s')])->fetchColumn();}public function countOpenMovements():int{return(int)$this->stmt("SELECT COUNT(*) FROM scanner_movimientos WHERE estado='abierto'")->fetchColumn();}public function countOverdue(\DateTimeImmutable$a):int{return(int)$this->stmt("SELECT COUNT(*) FROM scanner_movimientos WHERE estado IN('abierto','vencido') AND vence_at<:a",['a'=>$a->format('Y-m-d H:i:s')])->fetchColumn();}public function countOpenIncidents():int{return(int)$this->stmt("SELECT COUNT(*) FROM scanner_incidencias WHERE estado NOT IN('resuelta','descartada')")->fetchColumn();}public function incidentsBySeverity():array{return$this->stmt("SELECT severidad,COUNT(*) total FROM scanner_incidencias WHERE estado NOT IN('resuelta','descartada') GROUP BY severidad")->fetchAll(\PDO::FETCH_ASSOC);}public function topIncidentScanners(int$l):array{return$this->stmt('SELECT scanner_id,COUNT(*) total FROM scanner_incidencias GROUP BY scanner_id ORDER BY total DESC LIMIT '.max(1,min(100,$l)))->fetchAll(\PDO::FETCH_ASSOC);}public function topAreas(int$l):array{return$this->stmt('SELECT area_id,COUNT(*) total FROM scanner_movimientos WHERE area_id IS NOT NULL GROUP BY area_id ORDER BY total DESC LIMIT '.max(1,min(100,$l)))->fetchAll(\PDO::FETCH_ASSOC);}public function topUsers(int$l):array{return$this->stmt('SELECT entrega_registrada_por usuario_id,COUNT(*) total FROM scanner_movimientos WHERE entrega_registrada_por IS NOT NULL GROUP BY entrega_registrada_por ORDER BY total DESC LIMIT '.max(1,min(100,$l)))->fetchAll(\PDO::FETCH_ASSOC);}public function movementTimeStatistics(\DateTimeImmutable$f,\DateTimeImmutable$t):array{$v=$this->stmt('SELECT AVG(duracion_segundos) promedio,MIN(duracion_segundos) minimo,MAX(duracion_segundos) maximo FROM scanner_movimientos WHERE recibido_at BETWEEN :f AND :t AND duracion_segundos IS NOT NULL',['f'=>$f->format('Y-m-d H:i:s'),'t'=>$t->format('Y-m-d H:i:s')])->fetch(\PDO::FETCH_ASSOC);return$v?:[];}public function outOfServiceTime(\DateTimeImmutable$f,\DateTimeImmutable$t):array{throw new \LogicException('El esquema actual no conserva historial de transiciones para calcular tiempo fuera de servicio.');}}
